package com.ecoPedal.backend.entity;import java.time.LocalDateTime;import jakarta.persistence.*;import lombok.Getter;import lombok.Setter;import lombok.NoArgsConstructor;import lombok.AllArgsConstructor;@Getter@Setter@NoArgsConstructor@AllArgsConstructor@Entity@Table(name = "echange")public class Echange {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @Column(nullable = false)    private LocalDateTime dateEchange ;    @Column(nullable = false)    private Integer pointsDepenses;    @ManyToOne    @JoinColumn(name = "id_utilisateur" ,nullable = false)    private Utilisateur utilisateur;    @ManyToOne    @JoinColumn(name = "id_recompense" ,nullable = false)    private Recompense recompense ;}